<script setup lang="ts">
import { computed, ref } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { Clock, Document, RefreshRight, VideoPause } from '@element-plus/icons-vue'
import PageHeader from '@/components/PageHeader.vue'
import StatusPill from '@/components/StatusPill.vue'
import { asyncTasks } from '@/data/mock'

const status = ref('all')
const tasks = ref(asyncTasks.map((item) => ({ ...item })))
const selected = ref(tasks.value[0])
const filtered = computed(() => tasks.value.filter((task) => status.value === 'all' || task.status === status.value))
async function cancel() { await ElMessageBox.confirm('将安全停止后续批次，已经写入的有效结果会保留。确认取消？','取消长时任务',{type:'warning'}); selected.value.status='failed'; ElMessage.success('取消请求已提交') }
function retry() { selected.value.status='queued'; selected.value.progress=0; selected.value.step='已重新进入队列'; ElMessage.success('任务已重新入队，幂等键保持不变') }
</script>

<template>
  <div>
    <PageHeader title="长时任务中心" eyebrow="ASYNC JOBS" description="统一跟踪文档解析、批量出题、计划生成与报告任务。"><span class="worker-state"><i></i>3 个 Worker 在线</span><el-button plain><el-icon><RefreshRight /></el-icon>刷新</el-button></PageHeader>
    <section class="task-stats"><div><span>处理中</span><strong>1</strong><small>worker-02</small></div><div><span>排队中</span><strong>2</strong><small>预计等待 1 分钟</small></div><div><span>今日完成</span><strong class="green">8</strong><small>成功率 94%</small></div><div><span>平均耗时</span><strong>2m 18s</strong><small>较昨日 -16%</small></div><div class="infra"><span><i></i>Redis 正常</span><span><i></i>Celery 正常</span><span><i></i>PostgreSQL 正常</span></div></section>
    <section class="tasks-layout">
      <article class="content-card task-list-card"><div class="list-head"><div><h2>任务列表</h2><p>今天 · 共 6 个任务</p></div><el-radio-group v-model="status" size="small"><el-radio-button value="all">全部</el-radio-button><el-radio-button value="processing">处理中</el-radio-button><el-radio-button value="success">已完成</el-radio-button></el-radio-group></div>
        <button v-for="task in filtered" :key="task.id" class="task-entry" :class="{ active:selected.id===task.id }" @click="selected=task"><span class="entry-icon"><el-icon><component :is="task.type==='document_parse'?Document:Clock" /></el-icon></span><div class="entry-main"><div><b>{{ task.name }}</b><StatusPill :status="task.status" /></div><p>{{ task.step }}</p><el-progress v-if="task.status!=='success'" :percentage="task.progress" :show-text="false" :stroke-width="6" :color="task.status==='retrying'?'#e69448':'#6170e8'" /><small><span class="mono">{{ task.id }}</span><span>{{ task.createdAt }}</span></small></div><strong v-if="task.status!=='success'">{{ task.progress }}%</strong></button>
        <div class="older-label">昨天</div><button class="task-entry"><span class="entry-icon"><el-icon><Document /></el-icon></span><div class="entry-main"><div><b>课程知识点批量提取</b><StatusPill status="success" /></div><p>提取 36 个知识点与 42 条依赖关系</p><small><span class="mono">tsk_20260713_e05b</span><span>昨天 18:42</span></small></div></button>
      </article>

      <aside class="content-card detail-panel"><header><div><span>任务详情</span><StatusPill :status="selected.status" /></div><h2>{{ selected.name }}</h2><p class="mono">{{ selected.id }}</p></header><div class="detail-progress"><strong>{{ selected.progress }}<small>%</small></strong><el-progress :percentage="selected.progress" :show-text="false" :stroke-width="8" /><span>{{ selected.step }}</span></div><div class="detail-info"><p><span>任务类型</span><b>{{ selected.type }}</b></p><p><span>创建时间</span><b>2026-07-14 {{ selected.createdAt }}</b></p><p><span>开始时间</span><b>09:42:08</b></p><p><span>执行节点</span><b>celery@worker-02</b></p><p><span>重试次数</span><b>{{ selected.status==='retrying'?'1 / 3':'0 / 3' }}</b></p><p><span>幂等键</span><b class="mono">doc:1:v2:parse</b></p></div><div class="log-box"><div><h3>实时日志</h3><span>自动滚动</span></div><p><i>10:01:28</i> batch 8/12 embedding completed</p><p><i>10:01:29</i> inserted 96 chunks into pgvector</p><p><i>10:01:30</i> progress updated to {{ selected.progress }}%</p><p class="active"><i>10:01:31</i> processing batch 9/12...</p></div><div class="detail-actions"><el-button v-if="selected.status==='processing'" type="danger" plain @click="cancel"><el-icon><VideoPause /></el-icon>取消任务</el-button><el-button v-if="selected.status==='retrying'||selected.status==='failed'" type="primary" @click="retry"><el-icon><RefreshRight /></el-icon>立即重试</el-button><el-button plain>查看完整日志</el-button></div></aside>
    </section>
  </div>
</template>

